<script setup lang="ts">import{computed,ref}from'vue';import{useRoute}from'vue-router';import{X,BookOpen,ChevronDown}from'lucide-vue-next';import{useCourseStore}from'@/stores/courses';import LessonPlayer from '@/components/lesson/LessonPlayer.vue';const route=useRoute(),store=useCourseStore();const course=computed(()=>store.findCourse(String(route.params.courseId)));const lessons=computed(()=>course.value?.modules.flatMap(m=>m.lessons)??[]);const selectedId=ref('');const selected=computed(()=>lessons.value.find(l=>l.id===selectedId.value)||lessons.value[0])</script><template><div v-if="course" class="course-preview"><aside><div class="preview-brand"><BookOpen/>{{course.title}}</div><div v-for="module in course.modules" :key="module.id" class="preview-module"><b><ChevronDown/>{{module.title}}</b><button v-for="lesson in module.lessons" :key="lesson.id" :class="{active:selected?.id===lesson.id}" @click="selectedId=lesson.id">{{lesson.title}}<small>{{lesson.duration}} мин</small></button></div></aside><main><header><span>Режим ученика</span><RouterLink :to="`/app/courses/${course.id}`" class="icon-button"><X/></RouterLink></header><LessonPlayer v-if="selected" :lesson="selected"/></main></div><section v-else class="empty-state"><h2>Курс не найден</h2></section></template>